    /// <summary>
    /// Regista um NPC como resgatado nesta área. Se "npcId" for fornecido, a
    /// operação é idempotente — chamadas repetidas com o mesmo ID não duplicam a
    /// contagem nem disparam eventos novamente. Se "npcId" for vazio/nulo, o
    /// comportamento antigo é mantido (incrementa sem verificar duplicados).
    ///
    /// Quando "npcId" é fornecido:
    ///   • Adiciona o ID a <see cref="AreaProgress.rescuedNpcIds"/>.
    ///   • Incrementa <see cref="AreaProgress.npcsRescued"/> (limitado ao total da área).
    ///   • Define automaticamente a variável global "NpcResgatado_&lt;npcId&gt;" = true em
    ///     <see cref="GameVariables"/> — permite usar Condition_BoolVariable para
    ///     verificar o resgate sem configurar Action_SetBoolVariable manualmente.
    ///   • Sincroniza a população da vila correspondente em WorldState.
    /// </summary>
    public void AddNpcRescued(AreaData area, string npcId = null)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);

        // Idempotência: se o npcId já está na lista, não fazer nada.
        if (!string.IsNullOrEmpty(npcId) && ap.rescuedNpcIds.Contains(npcId))
            return;

        // Registar o ID (se fornecido).
        if (!string.IsNullOrEmpty(npcId))
        {
            ap.rescuedNpcIds.Add(npcId);

            // Variável automática: permite Condition_BoolVariable sem configuração extra.
            GameVariables.Instance?.SetBool($"NpcResgatado_{npcId}", true);
        }

        ap.npcsRescued = area.totalNpcsToRescue > 0
            ? Mathf.Min(ap.npcsRescued + 1, area.totalNpcsToRescue)
            : ap.npcsRescued + 1;

        // Auto-sync: actualiza WorldState.villagePopulations para que o HUD e
        // outros sistemas (música, lojas, decoração) reflictam o resgate imediatamente.
        SyncVillagePopulationForWorld(area.world);
    }

    /// <summary>
    /// Re-calcula e sincroniza a população de uma vila específica (world.mainVillageId)
    /// somando todos os npcsRescued e totalNpcsToRescue das áreas desse mundo.
    /// Chamado automaticamente por AddNpcRescued e pode ser chamado externamente.
    /// </summary>
    public void SyncVillagePopulationForWorld(WorldData world)
    {
        if (world == null || string.IsNullOrEmpty(world.mainVillageId)) return;
        var db = GameDatabase.Instance;
        var ws = WorldState.Instance;
        if (db == null || ws == null) return;

        int totalRescued = 0, totalMax = 0;
        foreach (var a in db.areas)
        {
            if (a == null || a.world != world) continue;
            totalRescued += GetNpcsRescued(a);
            totalMax += a.totalNpcsToRescue;
        }
        ws.SyncRescuedPopulation(world.mainVillageId, totalRescued, totalMax);
    }

    /// <summary>
    /// Re-calcula e sincroniza a população de TODAS as vilas a partir dos resgates
    /// registados. Chamado por WorldState.RestoreFrom após carregar um save, para
    /// garantir consistência mesmo em saves criados antes desta sincronização ser
    /// implementada.
    /// </summary>
    public void SyncAllVillagePopulations()
    {
        var db = GameDatabase.Instance;
        if (db == null) return;

        // Agrupa áreas por mundo e soma os contadores.
        var totals = new System.Collections.Generic.Dictionary<string, (int rescued, int max)>();
        foreach (var area in db.areas)
        {
            if (area == null || area.world == null) continue;
            string vid = area.world.mainVillageId;
            if (string.IsNullOrEmpty(vid)) continue;
            if (!totals.ContainsKey(vid)) totals[vid] = (0, 0);
            var t = totals[vid];
            totals[vid] = (t.rescued + GetNpcsRescued(area), t.max + area.totalNpcsToRescue);
        }

        var ws = WorldState.Instance;
        if (ws == null) return;
        foreach (var kv in totals)
            ws.SyncRescuedPopulation(kv.Key, kv.Value.rescued, kv.Value.max);
    }

