    /// <summary>
    /// Regista mais um Eco Perdido encontrado nesta área (limitado a
    /// AreaData.totalEcosPerdidos, se fornecida) e dá +1 ao saldo global de
    /// Ecos Perdidos do jogador (GiveEcosPerdidos, que actualiza o evento).
    /// </summary>
    public void AddEcoPerdidoFound(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        int before = ap.ecosPerdidosFound;
        ap.ecosPerdidosFound = area.totalEcosPerdidos > 0
            ? Mathf.Min(ap.ecosPerdidosFound + 1, area.totalEcosPerdidos)
            : ap.ecosPerdidosFound + 1;

        if (ap.ecosPerdidosFound > before)
            GiveEcosPerdidos(1);
    }

