    /// <summary>
    /// Regista a melodia "melodyId" como colectada e incrementa o contador da
    /// área "area" (se fornecida). Idempotente — não duplica.
    /// Dispara <see cref="PickupCollected"/> (PickupType.WildMelody) para que
    /// sistemas externos (EmblemManager, UI, etc.) possam reagir.
    /// </summary>
    public void MarkMelodyCollected(string melodyId, AreaData area)
    {
        if (string.IsNullOrEmpty(melodyId)) return;
        if (collectedMelodyIds.Contains(melodyId)) return;

        collectedMelodyIds.Add(melodyId);

        if (area != null)
        {
            var ap = GetOrCreateAreaProgress(area.areaId);
            ap.melodiesFound = area.totalMelodies > 0
                ? Mathf.Min(ap.melodiesFound + 1, area.totalMelodies)
                : ap.melodiesFound + 1;
        }

        // Notifica o EmblemManager e outros sistemas.
        PickupCollected?.Invoke(PickupType.WildMelody, melodyId);

        // Verifica se o desbloqueio de uma melodia completa o 100% da área
        // ou do jogo → dispara CheckAll do EmblemManager.
        EmblemManager.Instance?.CheckAll();
    }

