    /// <summary>
    /// Percentagem de conclusão de uma área (0–100), considerando apenas
    /// conteúdo permanente. Critérios que entram no cálculo:
    ///   • Runas de Gaia
    ///   • NPCs resgatados
    ///   • Sussurros da Terra encontrados (whispersFound — a entrega é contada
    ///     no total global, não nesta vista por área)
    ///   • Baús abertos
    ///   • Fragmentos Vitais recolhidos
    ///   • Animal libertado (area.freedAnimalForm)
    ///   • Desafio opcional concluído (area.hasOptionalChallenge)
    ///   • Melodias Selvagens recolhidas (area.totalMelodies)
    ///
    /// Excluídos: Sementes, Ecos Perdidos, inimigos.
    /// </summary>
    public int GetAreaCompletionPercent(AreaData area)
    {
        if (area == null) return 0;

        var ap = GetOrCreateAreaProgress(area.areaId);

        int total = 0;
        int found = 0;

        if (area.totalRunas > 0) { total += area.totalRunas; found += Mathf.Min(ap.runasFound, area.totalRunas); }
        if (area.totalNpcsToRescue > 0) { total += area.totalNpcsToRescue; found += Mathf.Min(ap.npcsRescued, area.totalNpcsToRescue); }
        if (area.totalWhispers > 0) { total += area.totalWhispers; found += Mathf.Min(ap.whispersFound, area.totalWhispers); }
        if (area.totalChests > 0) { total += area.totalChests; found += Mathf.Min(ap.chestsFound, area.totalChests); }
        if (area.totalFragments > 0) { total += area.totalFragments; found += Mathf.Min(ap.fragmentsFound, area.totalFragments); }

        if (area.freedAnimalForm != null)
        {
            total += 1;
            if (freedAnimalIds.Contains(area.freedAnimalForm.formId)) found += 1;
        }

        if (area.hasOptionalChallenge)
        {
            total += 1;
            if (ap.challengeCompleted) found += 1;
        }

        if (area.totalMelodies > 0) { total += area.totalMelodies; found += Mathf.Min(ap.melodiesFound, area.totalMelodies); }

        if (total <= 0) return 0;
        return Mathf.RoundToInt(100f * found / total);
    }

    private AreaProgress GetOrCreateAreaProgress(string areaId)
    {
        for (int i = 0; i < areaProgress.Count; i++)
            if (areaProgress[i].areaId == areaId) return areaProgress[i];

        var created = new AreaProgress { areaId = areaId };
        areaProgress.Add(created);
        return created;
    }

