    // ---------------- Percentagem Total do Save (Menu de Pausa: Progresso — Tarefa #11) ----------------

    /// <summary>
    /// Percentagem total de conclusão do save (0–100, ou exactamente 101 —
    /// GDD: "100% = Emblema de Gaia; Provação = Emblema de Apolo;
    /// Gaia + Apolo = 101% e Emblema de Zeus").
    ///
    /// <b>Critérios por área (allAreas):</b>
    ///   • Runas de Gaia (totalRunas)
    ///   • NPCs resgatados (totalNpcsToRescue)
    ///   • Sussurros da Terra: encontrados (whispersFound) + entregues
    ///     (whispersDelivered) — cada Sussurro conta duas vezes (encontrar
    ///     + entregar são passos distintos)
    ///   • Baús (totalChests)
    ///   • Fragmentos Vitais (totalFragments)
    ///   • Desafio opcional concluído (hasOptionalChallenge)
    ///   • Melodias Selvagens recolhidas (totalMelodies)
    ///
    /// <b>Critérios globais:</b>
    ///   • Formas de animais NÃO-secretas libertadas (allForms, isSecretForm=false)
    ///   • Missões concluídas (allMissions)
    ///   • Emblemas de mundo (allEmblems onde !isBonus &amp;&amp; !isGaiaEmblem
    ///     &amp;&amp; !isApoloEmblem — normalmente os 6 emblemas de mundo)
    ///
    /// <b>Excluídos do cálculo:</b>
    ///   • Formas secretas (isSecretForm = true)
    ///   • Emblema de Gaia, Emblema de Apolo, Emblema de Zeus (isGaiaEmblem /
    ///     isApoloEmblem / isBonus) — contam apenas para a regra dos 101%
    ///   • Sementes, Ecos Perdidos, inimigos
    ///
    /// <b>Regra especial de 101%:</b>
    ///   Devolve exactamente 101 se e só se Emblema de Gaia E Emblema de Apolo
    ///   estiverem ambos obtidos. Em todos os outros casos: clamp(0, 100).
    /// </summary>
    public int GetTotalCompletionPercent(List<AreaData> allAreas, List<AnimalFormData> allForms, List<MissionData> allMissions, List<EmblemData> allEmblems)
    {
        int total = 0;
        int found = 0;

        if (allAreas != null)
        {
            foreach (var area in allAreas)
            {
                if (area == null) continue;
                var ap = GetOrCreateAreaProgress(area.areaId);

                if (area.totalRunas > 0) { total += area.totalRunas; found += Mathf.Min(ap.runasFound, area.totalRunas); }
                if (area.totalNpcsToRescue > 0) { total += area.totalNpcsToRescue; found += Mathf.Min(ap.npcsRescued, area.totalNpcsToRescue); }

                if (area.totalWhispers > 0)
                {
                    total += area.totalWhispers; found += Mathf.Min(ap.whispersFound, area.totalWhispers);
                    total += area.totalWhispers; found += Mathf.Min(ap.whispersDelivered, area.totalWhispers);
                }

                if (area.totalChests > 0) { total += area.totalChests; found += Mathf.Min(ap.chestsFound, area.totalChests); }
                if (area.totalFragments > 0) { total += area.totalFragments; found += Mathf.Min(ap.fragmentsFound, area.totalFragments); }

                if (area.hasOptionalChallenge)
                {
                    total += 1;
                    if (ap.challengeCompleted) found += 1;
                }

                if (area.totalMelodies > 0) { total += area.totalMelodies; found += Mathf.Min(ap.melodiesFound, area.totalMelodies); }
            }
        }

        if (allForms != null)
        {
            foreach (var form in allForms)
            {
                if (form == null) continue;
                if (form.isSecretForm) continue; // formas secretas excluídas do cálculo.

                total += 1;
                if (HasFreedAnimal(form.formId)) found += 1;
            }
        }

        if (allMissions != null)
        {
            var missionManager = MissionManager.Instance;
            foreach (var mission in allMissions)
            {
                if (mission == null) continue;
                total += 1;
                if (missionManager != null && missionManager.IsMissionCompleted(mission)) found += 1;
            }
        }

        // Emblemas: só os 6 de mundo (não-bónus, não-Gaia, não-Apolo) contam.
        // Emblemas de Gaia e Apolo são rastreados separadamente para a regra dos 101%.
        bool gaiaObtained = false;
        bool apoloObtained = false;

        if (allEmblems != null)
        {
            var vars = GameVariables.Instance;
            foreach (var emblem in allEmblems)
            {
                if (emblem == null) continue;
                bool obtained = vars != null && !string.IsNullOrEmpty(emblem.obtainedVariable) && vars.GetBool(emblem.obtainedVariable);

                if (emblem.isGaiaEmblem)  { if (obtained) gaiaObtained  = true; continue; }
                if (emblem.isApoloEmblem) { if (obtained) apoloObtained = true; continue; }
                if (emblem.isBonus) continue; // outros bónus (ex: Emblema de Zeus) — excluídos.

                total += 1;
                if (obtained) found += 1;
            }
        }

        if (total <= 0) return 0;

        // GDD: 101% é exclusivo de Gaia + Apolo — nunca mais do que isso.
        int basePercent = Mathf.Clamp(Mathf.RoundToInt(100f * found / total), 0, 100);
        return (gaiaObtained && apoloObtained) ? 101 : basePercent;
    }

