    // ---------------- Snapshots de Status (Eventos NPC) ----------------
    //
    // Snapshots são guardados apenas em runtime (não persistidos em save files).
    // Usados por NPCs que "roubam" temporariamente recursos/animais ao player e
    // os devolvem mais tarde.
    //
    // A configuração do que guardar fica nas NPC actions
    // (Action_SavePlayerSnapshot / Action_RestorePlayerSnapshot) — ver
    // NPC/Actions/StatusSnapshotActions.cs.

    private readonly Dictionary<string, PlayerSnapshot> _snapshots =
        new Dictionary<string, PlayerSnapshot>();

    /// <summary>
    /// Guarda um snapshot com a chave indicada. Substitui qualquer snapshot
    /// anterior com a mesma chave.
    /// </summary>
    public void StoreSnapshot(string key, PlayerSnapshot snapshot)
    {
        if (string.IsNullOrEmpty(key) || snapshot == null) return;
        _snapshots[key] = snapshot;
    }

    /// <summary>
    /// Tenta obter o snapshot com a chave indicada. Devolve false se não existir.
    /// </summary>
    public bool TryGetSnapshot(string key, out PlayerSnapshot snapshot)
    {
        if (string.IsNullOrEmpty(key)) { snapshot = null; return false; }
        return _snapshots.TryGetValue(key, out snapshot);
    }

    /// <summary>
    /// Remove o snapshot com a chave indicada (após restaurar, para não
    /// ficar em memória desnecessariamente).
    /// </summary>
    public void DiscardSnapshot(string key)
    {
        if (!string.IsNullOrEmpty(key)) _snapshots.Remove(key);
    }

    /// <summary>Remove todos os snapshots em runtime (ex: ao iniciar novo jogo).</summary>
    public void ClearAllSnapshots() => _snapshots.Clear();

    // ---------------- Save / Load ----------------

    /// <summary>Versão actual da estrutura de save (ver SaveData.saveVersion).</summary>
    public const int CurrentSaveVersion = 1;

    /// <summary>Copia o estado actual para "data" (usado por SaveManager ao gravar).</summary>
    public void CaptureTo(SaveData data)
    {
        data.saveVersion = CurrentSaveVersion;

        data.currentHearts = currentHearts;
        data.maxHearts = maxHearts;

        data.sementes = sementes;
        data.runasDeGaia = runasDeGaia;
        data.totalRunasDeGaiaCollected = totalRunasDeGaiaCollected;
        data.brotosDeVida = brotosDeVida;
        data.fragmentosVitais = fragmentosVitais;
        data.runasDeApolo = runasDeApolo;

        data.ecosPerdidos = ecosPerdidos;
        data.totalEcosPerdidosCollected = totalEcosPerdidosCollected;

        data.inventory = new List<InventoryEntry>();
        foreach (var entry in inventory)
            data.inventory.Add(new InventoryEntry { itemId = entry.itemId, quantity = entry.quantity });

        data.equippedItemId = equippedItemId;

        data.collectedSpecialItemIds = new List<string>(collectedSpecialItemIds);
        data.defeatedEnemyIds = new List<string>(defeatedEnemyIds);
        data.collectedPickupIds = new List<string>(collectedPickupIds);

        data.collectedMelodyIds = new List<string>(collectedMelodyIds);
        data.completedChallengeIds = new List<string>(completedChallengeIds);

        data.challengeRecords = new List<ChallengeRecord>();
        foreach (var record in challengeRecords)
            if (record != null) data.challengeRecords.Add(new ChallengeRecord { challengeId = record.challengeId, bestTimeSeconds = record.bestTimeSeconds });

        data.totalSementesCollected = totalSementesCollected;
        data.totalFragmentosVitaisCollected = totalFragmentosVitaisCollected;
        data.totalBrotosDeVidaCollected = totalBrotosDeVidaCollected;
        data.totalSussurrosCollected = totalSussurrosCollected;
        data.totalChestsOpenedGlobal = totalChestsOpenedGlobal;

        data.isNewGamePlus = isNewGamePlus;

        data.freedAnimalIds = new List<string>(freedAnimalIds);
        data.unlockedUpgradeIds = new List<string>(unlockedUpgradeIds);
        data.enabledUpgradeIds = new List<string>(enabledUpgradeIds);

        // Nota: o Modo Difícil ("Juramento Difícil") já não tem campo próprio —
        // é derivado de enabledUpgradeIds (ver IsHardModeActive), já guardado acima.
        data.lastCheckpointId = lastCheckpointId;

        data.areaProgress = new List<AreaProgress>();
        foreach (var ap in areaProgress)
            data.areaProgress.Add(new AreaProgress
            {
                areaId = ap.areaId,
                deaths = ap.deaths,
                visited = ap.visited,
                opened = ap.opened,
                runasFound = ap.runasFound,
                npcsRescued = ap.npcsRescued,
                rescuedNpcIds = new List<string>(ap.rescuedNpcIds),
                whispersFound = ap.whispersFound,
                whispersDelivered = ap.whispersDelivered,
                chestsFound = ap.chestsFound,
                fragmentsFound = ap.fragmentsFound,
                ecosPerdidosFound = ap.ecosPerdidosFound,
                challengeCompleted = ap.challengeCompleted,
                challengeDiscovered = ap.challengeDiscovered,
                melodiesFound = ap.melodiesFound,
                sussurrosDaTerraOuvidos = new List<string>(ap.sussurrosDaTerraOuvidos)
            });

        data.defeatedBossWorldIds = new List<string>(defeatedBossWorldIds);
        data.pendingPostBossReturnWorldIds = new List<string>(pendingPostBossReturnWorldIds);

        data.worldProgress = new List<WorldProgress>();
        foreach (var wp in worldProgress)
            data.worldProgress.Add(new WorldProgress { worldId = wp.worldId, totalsDiscovered = wp.totalsDiscovered });

        data.obtainedClueIds = new List<string>(obtainedClueIds);
        data.heardRumorIds = new List<string>(heardRumorIds);
        data.foundRumorIds = new List<string>(foundRumorIds);

        data.unlockedAreaIds = new List<string>(unlockedAreaIds);
        data.discoveredBossWorldIds = new List<string>(discoveredBossWorldIds);
        data.bossUnlockAnimationPlayedWorldIds = new List<string>(bossUnlockAnimationPlayedWorldIds);
        data.apoloAreaUnlockAnimationPlayed = apoloAreaUnlockAnimationPlayed;

        // Snapshots activos (ex: sequência de roubo em curso).
        data.activeSnapshots = new List<SaveData.SnapshotEntry>();
        foreach (var kv in _snapshots)
            data.activeSnapshots.Add(new SaveData.SnapshotEntry { key = kv.Key, snapshot = kv.Value });
    }

    /// <summary>Restaura o estado a partir de "data" (usado por SaveManager ao carregar).</summary>
    public void RestoreFrom(SaveData data)
    {
        if (data == null) return;

        maxHearts = Mathf.Min(data.maxHearts, MaxHeartsCap);
        currentHearts = Mathf.Clamp(data.currentHearts, 0, maxHearts);

        sementes = data.sementes;
        runasDeGaia = data.runasDeGaia;
        totalRunasDeGaiaCollected = data.totalRunasDeGaiaCollected;
        brotosDeVida = data.brotosDeVida;
        fragmentosVitais = data.fragmentosVitais;
        runasDeApolo = data.runasDeApolo;

        ecosPerdidos = data.ecosPerdidos;
        totalEcosPerdidosCollected = data.totalEcosPerdidosCollected;

        inventory.Clear();
        if (data.inventory != null)
            foreach (var entry in data.inventory)
                inventory.Add(new InventoryEntry { itemId = entry.itemId, quantity = entry.quantity });

        equippedItemId = data.equippedItemId;

        collectedSpecialItemIds.Clear();
        if (data.collectedSpecialItemIds != null) collectedSpecialItemIds.AddRange(data.collectedSpecialItemIds);

        defeatedEnemyIds.Clear();
        if (data.defeatedEnemyIds != null) defeatedEnemyIds.AddRange(data.defeatedEnemyIds);

        collectedPickupIds.Clear();
        if (data.collectedPickupIds != null) collectedPickupIds.AddRange(data.collectedPickupIds);

        collectedMelodyIds.Clear();
        if (data.collectedMelodyIds != null) collectedMelodyIds.AddRange(data.collectedMelodyIds);

        completedChallengeIds.Clear();
        if (data.completedChallengeIds != null) completedChallengeIds.AddRange(data.completedChallengeIds);

        challengeRecords.Clear();
        if (data.challengeRecords != null)
            foreach (var record in data.challengeRecords)
                if (record != null) challengeRecords.Add(new ChallengeRecord { challengeId = record.challengeId, bestTimeSeconds = record.bestTimeSeconds });

        totalSementesCollected = data.totalSementesCollected;
        totalFragmentosVitaisCollected = data.totalFragmentosVitaisCollected;
        totalBrotosDeVidaCollected = data.totalBrotosDeVidaCollected;
        totalSussurrosCollected = data.totalSussurrosCollected;
        totalChestsOpenedGlobal = data.totalChestsOpenedGlobal;

        isNewGamePlus = data.isNewGamePlus;

        freedAnimalIds.Clear();
        if (data.freedAnimalIds != null) freedAnimalIds.AddRange(data.freedAnimalIds);

        unlockedUpgradeIds.Clear();
        if (data.unlockedUpgradeIds != null) unlockedUpgradeIds.AddRange(data.unlockedUpgradeIds);

        enabledUpgradeIds.Clear();
        if (data.enabledUpgradeIds != null) enabledUpgradeIds.AddRange(data.enabledUpgradeIds);

        // Nota: o Modo Difícil ("Juramento Difícil") já não tem campo próprio —
        // é derivado de enabledUpgradeIds (ver IsHardModeActive), já restaurado acima.
        lastCheckpointId = data.lastCheckpointId;

        areaProgress.Clear();
        if (data.areaProgress != null)
            foreach (var ap in data.areaProgress)
                areaProgress.Add(new AreaProgress
                {
                    areaId = ap.areaId,
                    deaths = ap.deaths,
                    visited = ap.visited,
                    opened = ap.opened,
                    runasFound = ap.runasFound,
                    npcsRescued = ap.npcsRescued,
                    rescuedNpcIds = ap.rescuedNpcIds != null ? new List<string>(ap.rescuedNpcIds) : new List<string>(),
                    whispersFound = ap.whispersFound,
                    whispersDelivered = ap.whispersDelivered,
                    chestsFound = ap.chestsFound,
                    fragmentsFound = ap.fragmentsFound,
                    ecosPerdidosFound = ap.ecosPerdidosFound,
                    challengeCompleted = ap.challengeCompleted,
                    challengeDiscovered = ap.challengeDiscovered,
                    melodiesFound = ap.melodiesFound,
                    sussurrosDaTerraOuvidos = ap.sussurrosDaTerraOuvidos != null ? new List<string>(ap.sussurrosDaTerraOuvidos) : new List<string>()
                });

        // Migração: saves versão 0 (sem rescuedNpcIds) — aceitar inconsistência.
        // Os rescuedNpcIds ficam vazios; novas chamadas a AddNpcRescued passam a
        // funcionar correctamente com idempotência. Salvar novamente para converter.
        // (Nenhuma acção extra necessária — os IDs são preenchidos ao resgatar NPCs.)

        defeatedBossWorldIds.Clear();
        if (data.defeatedBossWorldIds != null) defeatedBossWorldIds.AddRange(data.defeatedBossWorldIds);

        pendingPostBossReturnWorldIds.Clear();
        if (data.pendingPostBossReturnWorldIds != null) pendingPostBossReturnWorldIds.AddRange(data.pendingPostBossReturnWorldIds);

        worldProgress.Clear();
        if (data.worldProgress != null)
            foreach (var wp in data.worldProgress)
                worldProgress.Add(new WorldProgress { worldId = wp.worldId, totalsDiscovered = wp.totalsDiscovered });

        obtainedClueIds.Clear();
        if (data.obtainedClueIds != null) obtainedClueIds.AddRange(data.obtainedClueIds);

        heardRumorIds.Clear();
        if (data.heardRumorIds != null) heardRumorIds.AddRange(data.heardRumorIds);

        foundRumorIds.Clear();
        if (data.foundRumorIds != null) foundRumorIds.AddRange(data.foundRumorIds);

        unlockedAreaIds.Clear();
        if (data.unlockedAreaIds != null) unlockedAreaIds.AddRange(data.unlockedAreaIds);

        discoveredBossWorldIds.Clear();
        if (data.discoveredBossWorldIds != null) discoveredBossWorldIds.AddRange(data.discoveredBossWorldIds);

        bossUnlockAnimationPlayedWorldIds.Clear();
        if (data.bossUnlockAnimationPlayedWorldIds != null) bossUnlockAnimationPlayedWorldIds.AddRange(data.bossUnlockAnimationPlayedWorldIds);

        apoloAreaUnlockAnimationPlayed = data.apoloAreaUnlockAnimationPlayed;

        // Snapshots activos — restaurar para que missões em curso (ex: ladrão)
        // continuem a funcionar após carregar um save gravado a meio da sequência.
        _snapshots.Clear();
        if (data.activeSnapshots != null)
            foreach (var entry in data.activeSnapshots)
                if (!string.IsNullOrEmpty(entry.key) && entry.snapshot != null)
                    _snapshots[entry.key] = entry.snapshot;
    }
}

/// <summary>Entrada do inventário com quantidade (Etapa 4.2).</summary>
[System.Serializable]
public class InventoryEntry
{
    public string itemId;
    [Min(0)] public int quantity = 1;
}

/// <summary>
/// Estado de progresso a nível de MUNDO (não de área) — usado pela secção
/// Progresso do Menu de Pausa (Tarefa #11).
/// </summary>
[System.Serializable]
public class WorldProgress
{
    public string worldId;

    /// <summary>
    /// O jogador já descobriu quantos Runas/Animais/NPCs/Sussurros/Missões
    /// existem neste mundo — enquanto false, a secção Progresso mostra "X/?"
    /// em vez do total real (GDD: "Poderia aparecer simplesmente 4/? até o
    /// jogador descobrir quantos existem naquele mundo").
    /// </summary>
    public bool totalsDiscovered;
}

[System.Serializable]
public class AreaProgress
{
    public string areaId;
    public int deaths;
    public bool visited;

    /// <summary>"Área aberta" — acesso desbloqueado (ex: porta/portão/ponte activados), distinto de "visited".</summary>
    public bool opened;

    // ---------------- Descobertas da Área (Menu de Pausa: Área Atual) ----------------

    /// <summary>Runas de Gaia encontradas nesta área (de AreaData.totalRunas).</summary>
    public int runasFound;

    /// <summary>NPCs resgatados nesta área (de AreaData.totalNpcsToRescue).</summary>
    public int npcsRescued;

    /// <summary>
    /// IDs dos NPCs já resgatados nesta área — garante idempotência em
    /// <see cref="PlayerProgress.AddNpcRescued"/>. Um NPC cujo ID já esteja nesta
    /// lista não incrementa "npcsRescued" nem dispara eventos novamente.
    /// Saves de versão 0 (anteriores à Tarefa NPC-ID) começam com lista vazia —
    /// novos resgates passam a registar-se correctamente a partir daí.
    /// </summary>
    public List<string> rescuedNpcIds = new List<string>();

    /// <summary>Sussurros da Terra encontrados nesta área (de AreaData.totalWhispers).</summary>
    public int whispersFound;

    /// <summary>
    /// Sussurros da Terra já ENTREGUES (a um NPC/altar), distinto de "encontrados"
    /// — usado em "Sussurros entregues" na secção Progresso do Menu de Pausa
    /// (Tarefa #11). Partilha o total com "whispersFound" (AreaData.totalWhispers).
    /// </summary>
    public int whispersDelivered;

    /// <summary>Baús abertos nesta área (de AreaData.totalChests).</summary>
    public int chestsFound;

    /// <summary>Fragmentos Vitais encontrados nesta área (de AreaData.totalFragments).</summary>
    public int fragmentsFound;

    /// <summary>Ecos Perdidos recolhidos nesta área (de AreaData.totalEcosPerdidos — normalmente 15 por área normal).</summary>
    public int ecosPerdidosFound;

    /// <summary>Melodias Selvagens encontradas nesta área (de AreaData.totalMelodies).</summary>
    public int melodiesFound;

    /// <summary>O desafio opcional desta área (se existir) foi concluído.</summary>
    public bool challengeCompleted;

    /// <summary>O jogador já descobriu/encontrou o desafio opcional desta área (mostra "?" até aqui).</summary>
    public bool challengeDiscovered;

    /// <summary>
    /// Frases exactas (ditas por NPCs) sobre esta área que o jogador já ouviu —
    /// mostradas em "SUSSURROS DA TERRA" na secção "Área Atual" do Menu de Pausa.
    /// É a mesma colecionável da contagem "Sussurros da Terra" (whispersFound).
    /// </summary>
    [FormerlySerializedAs("echoesHeard")]
    public List<string> sussurrosDaTerraOuvidos = new List<string>();
}

/// <summary>
/// Fotografia instantânea do estado do player tirada por um evento de NPC
/// (Action_SavePlayerSnapshot) e restaurada por outro (Action_RestorePlayerSnapshot).
///
/// Apenas os campos com o flag correspondente em "has*" foram efectivamente
/// capturados — restaurar só restaura esses campos, deixando o resto intacto.
///
/// Os snapshots são guardados apenas em runtime (não persistidos em save files).
/// Identificados por chave de texto configurada pelo designer na acção NPC.
///
/// Exemplo de uso:
///   NPC confisca animais ao entrar na área:
///     1. Action_SavePlayerSnapshot  (key="sela_animais", saveLockedForms=true, saveFreedAnimals=true)
///     2. Action_LockAllFormsExceptStart  (bloqueia a roda visualmente)
///   NPC devolve animais ao sair da área:
///     3. Action_RestorePlayerSnapshot (key="sela_animais")  → restaura locked forms e freed animals
///     4. Action_ClearFormLocks  (segurança extra)
/// </summary>
[System.Serializable]
public class PlayerSnapshot
{
    // ── Flags (o que foi capturado) ────────────────────────────────────────
    public bool hasSementes;
    public bool hasRunasDeGaia;
    public bool hasEcosPerdidos;
    public bool hasBrotosDeVida;
    public bool hasCurrentHearts;
    public bool hasMaxHearts;
    public bool hasInventory;
    public bool hasEquippedItem;
    public bool hasFreedAnimals;
    public bool hasLockedForms;

    // ── Valores capturados ─────────────────────────────────────────────────
    public int sementes;
    public int runasDeGaia;
    public int ecosPerdidos;
    public int brotosDeVida;
    public int currentHearts;
    public int maxHearts;
    public List<InventoryEntry> inventory;
    public string equippedItemId;
    public List<string> freedAnimalIds;
    /// <summary>formIds de formas bloqueadas pelo FormSwitcher no momento do snapshot.</summary>
    public List<string> lockedFormIds;
}
